<?php if (!defined('__ROOT_DIR__')) exit; ?>
<!DOCTYPE html><html lang="zh"><head><meta charset="UTF-8"><?php require_once __ROOT_DIR__.'/shipsay/seo.php'; list($seo_title,$seo_keywords,$seo_description)=ss_seo_render('rank'); $rank_sections=isset($top_sections)&&is_array($top_sections)?$top_sections:[]; $rank_lists=isset($top_rank_lists)&&is_array($top_rank_lists)?$top_rank_lists:[]; $rank_limit=isset($top_rank_limit)&&(int)$top_rank_limit>0?(int)$top_rank_limit:10; if(trim((string)$seo_title)===''||trim((string)$seo_title)===SITE_NAME)$seo_title='排行榜_'.SITE_NAME; if(trim((string)$seo_keywords)===''||trim((string)$seo_keywords)===SITE_NAME)$seo_keywords='排行榜,日榜,周榜,月榜,总榜,推荐榜,收藏榜,'.SITE_NAME; if(trim((string)$seo_description)===''||trim((string)$seo_description)===SITE_NAME)$seo_description=SITE_NAME.'小说排行榜聚合页。'; ?><title><?=htmlspecialchars($seo_title, ENT_QUOTES, 'UTF-8')?></title><meta name="keywords" content="<?=htmlspecialchars($seo_keywords, ENT_QUOTES, 'UTF-8')?>"><meta name="description" content="<?=htmlspecialchars($seo_description, ENT_QUOTES, 'UTF-8')?>"><?php require_once __THEME_DIR__ . '/tpl_header.php'; ?></head><body><?php ss_render_page_top(['page_title' => '排行榜', 'show_back' => true]); ?><?php if(!empty($rank_sections)): ?><div class="rank-tabs top-rank-tabs"><?php foreach($rank_sections as $conf): ?><a href="<?=htmlspecialchars((string)$conf['more'], ENT_QUOTES, 'UTF-8')?>"><?=htmlspecialchars((string)$conf['title'], ENT_QUOTES, 'UTF-8')?></a><?php endforeach; ?></div><?php endif; ?><div class="top-rank-grid"><?php foreach($rank_sections as $key=>$conf): $list=isset($rank_lists[$key])&&is_array($rank_lists[$key])?$rank_lists[$key]:[]; ?><div class="top-card"><div class="top-card-head"><h2><?=htmlspecialchars((string)$conf['title'], ENT_QUOTES, 'UTF-8')?></h2><a href="<?=htmlspecialchars((string)$conf['more'], ENT_QUOTES, 'UTF-8')?>">更多</a></div><ol class="top-card-list"><?php if(!empty($list)): foreach(array_slice($list,0,$rank_limit) as $i=>$v): ?><li><span class="rank-num"><?=$i+1?></span><a href="<?=htmlspecialchars((string)$v['info_url'], ENT_QUOTES, 'UTF-8')?>"><?=htmlspecialchars((string)$v['articlename'], ENT_QUOTES, 'UTF-8')?></a><em><?=htmlspecialchars((string)$v['author'], ENT_QUOTES, 'UTF-8')?></em></li><?php endforeach; else: ?><li class="rank-empty">暂无数据</li><?php endif; ?></ol></div><?php endforeach; ?></div><?php require_once __THEME_DIR__ . '/tpl_footer.php'; ?>
